SELECT h.*, ste.site_nm AS site_nm, cla.member_nm AS claim_nm, ord.member_nm AS order_nm, usr.user_nm AS chg_user_nm, cd_cs.code_label AS claim_status_cd_nm FROM odh_claim_status_hist h LEFT JOIN sy_site ste ON ste.site_id = h.site_id LEFT JOIN od_claim cla ON cla.claim_id = h.claim_id LEFT JOIN od_order ord ON ord.order_id = h.order_id LEFT JOIN sy_user usr ON usr.user_id = h.chg_user_id LEFT JOIN sy_code cd_cs ON cd_cs.code_grp = 'CLAIM_STATUS' AND cd_cs.code_value = h.claim_status_cd
ORDER BY h.claim_status_hist_id ASC ORDER BY h.claim_status_hist_id DESC ORDER BY h.reg_date ASC ORDER BY h.reg_date DESC ORDER BY h.reg_date DESC
LIMIT #{p.limit} OFFSET #{p.offset}

